# ------------------------------------------------------------------
# Graph nodes
# ------------------------------------------------------------------
def _nodes() -> list:
    return [
        helper.make_node('Add', inputs=['model_input', 'n0_aln_res'], outputs=['n0_aln_add']),
        helper.make_node('LayerNormalization', inputs=['n0_aln_add', 'n0_aln_sc', 'n0_aln_b'], outputs=['n0_aln_out'], axis=-1, epsilon=9.999999747378752e-06),
        helper.make_node('Conv', inputs=['n0_aln_out', 'n100_conv_w', 'n100_conv_b'], outputs=['n100_conv_cv'], kernel_shape=[3, 3], pads=[1, 1, 1, 1]),
        helper.make_node('Max', inputs=['n100_conv_cv', 'n100_conv_zero'], outputs=['n100_conv_mx']),
        helper.make_node('Div', inputs=['n100_conv_cv', 'n100_conv_alpha'], outputs=['n100_conv_div']),
        helper.make_node('Exp', inputs=['n100_conv_div'], outputs=['n100_conv_ex']),
        helper.make_node('Sub', inputs=['n100_conv_ex', 'n100_conv_one'], outputs=['n100_conv_sub']),
        helper.make_node('Mul', inputs=['n100_conv_sub', 'n100_conv_alpha'], outputs=['n100_conv_mu']),
        helper.make_node('Min', inputs=['n100_conv_mu', 'n100_conv_zero'], outputs=['n100_conv_mn']),
        helper.make_node('Add', inputs=['n100_conv_mx', 'n100_conv_mn'], outputs=['n100_conv_out']),
        helper.make_node('Pad', inputs=['n100_conv_out', 'n200_prc_pads'], outputs=['n200_prc_pad'], mode='reflect'),
        helper.make_node('Conv', inputs=['n200_prc_pad', 'n200_prc_w', 'n200_prc_b'], outputs=['n200_prc_out'], kernel_shape=[3, 3], pads=[0, 0, 0, 0]),
        helper.make_node('Add', inputs=['n200_prc_out', 'n300_faz_z'], outputs=['n300_faz_a']),
        helper.make_node('Mul', inputs=['n300_faz_a', 'n300_faz_o'], outputs=['n300_faz_out']),
        helper.make_node('MatMul', inputs=['n300_faz_out', 'n400_mm4d_w'], outputs=['n400_mm4d_out']),
    ]

# ------------------------------------------------------------------
# Model builder
# ------------------------------------------------------------------
def build_model() -> bytes:
    inputs_info  = [helper.make_tensor_value_info(INPUT_NAME, TensorProto.FLOAT, INPUT_SHAPE)]
    outputs_info = [helper.make_tensor_value_info(OUTPUT_NAME, TensorProto.FLOAT, OUTPUT_SHAPE)]
    graph = helper.make_graph(_nodes(), "bug_000031", inputs_info, outputs_info, initializer=_inits())
    model = helper.make_model(graph, opset_imports=[helper.make_opsetid("", OPSET)])
    model.ir_version = IR_VERSION
    return model.SerializeToString()


